<?php
$pageTitle='B2B Price Lists';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('b2b_price_lists');
$pdo=getDB();
$products=$pdo->query('SELECT id,name,sku,price FROM '.table('products').' WHERE active=1 ORDER BY name LIMIT 500')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'list');
    if($action==='item'){
      $pdo->prepare('INSERT INTO '.table('b2b_price_list_items').' (b2b_price_list_id,product_id,sku,base_price,special_price,min_quantity,max_quantity,status) VALUES (?,?,?,?,?,?,?,"active")')->execute([(int)$_POST['price_list_id'],(int)$_POST['product_id'],trim((string)$_POST['sku']),(float)$_POST['base_price'],(float)$_POST['special_price'],(float)$_POST['min_quantity'],(float)$_POST['max_quantity']]);
      flash('success','Price list item added.');
    } elseif($action==='defaults'){ecom33InstallDefaults($pdo);flash('success','Advanced ecommerce defaults installed.');}
    else{ecom33CreatePriceList($pdo,trim((string)$_POST['price_list_name']),trim((string)$_POST['customer_type']),(float)$_POST['discount_percent'],trim((string)$_POST['notes']));flash('success','B2B price list created.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'b2b-price-lists']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/b2b-price-lists.php');
}
$lists=$pdo->query('SELECT * FROM '.table('b2b_price_lists').' ORDER BY created_at DESC LIMIT 200')->fetchAll();
$items=$pdo->query('SELECT i.*,p.name product_name,l.price_list_name FROM '.table('b2b_price_list_items').' i LEFT JOIN '.table('products').' p ON p.id=i.product_id LEFT JOIN '.table('b2b_price_lists').' l ON l.id=i.b2b_price_list_id ORDER BY i.created_at DESC LIMIT 300')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">B2B Pricing</div><h2 class="h4 mb-1">B2B Price Lists</h2><p class="text-secondary mb-0">Create special product prices by customer type, quantity and price-list tier.</p></div><form method="post"><input type="hidden" name="action" value="defaults"><button class="btn btn-brand">Install Defaults</button></form></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Price List</h2><input class="form-control mb-2" name="price_list_name" placeholder="Workshop Gold Pricing" required><select class="form-select mb-2" name="customer_type"><option>b2b</option><option>b2c</option><option>dealer</option><option>reseller</option></select><input class="form-control mb-2" type="number" step="0.01" name="discount_percent" value="<?php echo esc(setting('default_b2b_discount_percent','5')); ?>"><textarea class="form-control mb-3" name="notes" rows="3"></textarea><button class="btn btn-brand w-100">Create List</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="item"><h2 class="h5 mb-3">Add Product Price</h2><select class="form-select mb-2" name="price_list_id"><?php foreach($lists as $l): ?><option value="<?php echo (int)$l['id']; ?>"><?php echo esc($l['price_list_number'].' · '.$l['price_list_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name'].' · '.money($p['price'])); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="sku" placeholder="SKU"><input class="form-control mb-2" type="number" step="0.01" name="base_price" placeholder="Base price"><input class="form-control mb-2" type="number" step="0.01" name="special_price" placeholder="Special price"><div class="row g-2 mb-3"><div class="col-6"><input class="form-control" type="number" step="0.01" name="min_quantity" value="1"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="max_quantity" value="0"></div></div><button class="btn btn-outline-primary w-100">Add Item</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Price Lists</h2><table class="table"><thead><tr><th>List</th><th>Type</th><th>Discount</th><th>Status</th></tr></thead><tbody><?php foreach($lists as $l): ?><tr><td><strong><?php echo esc($l['price_list_number']); ?></strong><div class="small text-secondary"><?php echo esc($l['price_list_name']); ?></div></td><td><?php echo esc($l['customer_type']); ?></td><td><?php echo number_format((float)$l['discount_percent'],2); ?>%</td><td><span class="badge bg-<?php echo esc(statusTone($l['status'])); ?>"><?php echo esc($l['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Price Items</h2><table class="table"><thead><tr><th>List</th><th>Product</th><th>Qty</th><th>Special Price</th></tr></thead><tbody><?php foreach($items as $i): ?><tr><td><?php echo esc($i['price_list_name']); ?></td><td><?php echo esc($i['product_name']); ?><div class="small text-secondary"><?php echo esc($i['sku']); ?></div></td><td><?php echo esc($i['min_quantity'].' - '.($i['max_quantity']?:'∞')); ?></td><td><?php echo money($i['special_price']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>